+        assert_eq!(WcWidth::from_char('\u{00a1}'), WcWidth::Ambiguous);
+        // U+00A4 CURRENCY SIGN
+        assert_eq!(WcWidth::from_char('\u{00a4}'), WcWidth::Ambiguous);
+    }
+
